import{_ as n,o as a,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"76A. Absences On Defence Leave","description":"","frontmatter":{"title":"76A. Absences On Defence Leave","eba":"Allied Health Professionals 2021-2026","topics":["leave","employment"]},"headers":[],"relativePath":"ebas/allied-health/leave/76A-absences-on-defence-leave.md","filePath":"ebas/allied-health/leave/76A-absences-on-defence-leave.md"}'),s={name:"ebas/allied-health/leave/76A-absences-on-defence-leave.md"};function r(i,e,l,c,d,h){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_76a-absences-on-defence-leave" tabindex="-1">76A. Absences On Defence Leave <a class="header-anchor" href="#_76a-absences-on-defence-leave" aria-label="Permalink to &quot;76A. Absences On Defence Leave&quot;">​</a></h1><p><strong>76A.1</strong> A Full-Time or Part-Time Employee absent on defence service will be reimbursed by the Employer an amount equal to the difference between:</p><p><strong>(a)</strong> the amount paid by the Defence Service (not including reimbursements) in respect of a period during which the Employee was absent on defence service; and</p><p><strong>(b)</strong> the amount the Employee could reasonably expect to have received from the Employer as earnings for that period had the Employee not been absent on defence service.</p><p><strong>76A.2</strong> An Employee will notify the Employer as soon as possible of the date they require absence on defence service. The Employee will give the Employer proof that the absence relates to defence service, the duration of such absence and the amount received for the relevant defence service period.</p><p><strong>76A.3</strong> In this clause &#39;absence on defence service&#39; has the meaning contained in</p><p>Example The Employee is on Defence Service leave for the duration of a particular pay period. Were the employee not on Defence Service leave in that pay period they would have worked on the Sunday and Monday evening shift of each week of the pay period. The Employee is entitled to payment as though at work for each of the Sunday and Monday evening shifts, less the amount of payment (not including reimbursements) from the Defence Service for the equivalent time of the Sunday and Monday evening shifts.</p><p>Plain language terms: ADF leave, reservist leave.</p>',8)])])}const m=n(s,[["render",r]]);export{f as __pageData,m as default};
